use std::io;
use std::collections::VecDeque;

fn main() {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    let mut iter = input.trim().split_whitespace();
    let w: usize = iter.next().unwrap().parse().unwrap();
    let h: usize = iter.next().unwrap().parse().unwrap();

    let mut grid: Vec<Vec<u8>> = Vec::with_capacity(h);
    for _ in 0..h {
        let mut line = String::new();
        io::stdin().read_line(&mut line).unwrap();
        grid.push(line.trim().bytes().collect());
    }

    eprintln!("Grid: {}x{}", w, h);

    let mut visited = vec![vec![false; w]; h];

    // Flood-fill from all border '.' cells to mark exterior
    let mut queue = VecDeque::new();
    for r in 0..h {
        for c in 0..w {
            if (r == 0 || r == h - 1 || c == 0 || c == w - 1) && grid[r][c] == b'.' {
                if !visited[r][c] {
                    visited[r][c] = true;
                    queue.push_back((r, c));
                }
            }
        }
    }

    // BFS to mark all exterior '.' cells
    while let Some((r, c)) = queue.pop_front() {
        for (dr, dc) in [(!0usize, 0), (1, 0), (0, !0usize), (0, 1)] {
            let nr = r.wrapping_add(dr);
            let nc = c.wrapping_add(dc);
            if nr < h && nc < w && !visited[nr][nc] && grid[nr][nc] == b'.' {
                visited[nr][nc] = true;
                queue.push_back((nr, nc));
            }
        }
    }

    // Count remaining unvisited '.' components = holes
    let mut holes = 0;
    for r in 0..h {
        for c in 0..w {
            if !visited[r][c] && grid[r][c] == b'.' {
                holes += 1;
                eprintln!("Hole found at ({}, {})", c, r);
                // BFS to mark this hole
                visited[r][c] = true;
                queue.push_back((r, c));
                while let Some((rr, cc)) = queue.pop_front() {
                    for (dr, dc) in [(!0usize, 0), (1, 0), (0, !0usize), (0, 1)] {
                        let nr = rr.wrapping_add(dr);
                        let nc = cc.wrapping_add(dc);
                        if nr < h && nc < w && !visited[nr][nc] && grid[nr][nc] == b'.' {
                            visited[nr][nc] = true;
                            queue.push_back((nr, nc));
                        }
                    }
                }
            }
        }
    }

    eprintln!("Total holes: {}", holes);
    println!("{}", holes);
}

